var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양.","JPN":"ミナさん。","ENG":"Mina.","TWN":"米娜小姐。"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양은 휴가임무 중이라고요.","JPN":"ミナさんは今、休暇任務を遂行しているんですよ？","ENG":"You're supposed to be on vacation right now.","TWN":"米娜小姐妳在休假啊。"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"기껏 부사장님이 놀이 공원까지 보내 줬는데, 그렇게 다짜고짜 달려들면 여기에 온 보람이 없잖아요.","JPN":"せっかく副社長が遊園地に来させてくれたのに、\\nそんなことしたら台無しじゃないですか。","ENG":"The VP even arranged for you to come to an amusement park. Running into battle like that defeats the purpose.","TWN":"副總好不容易讓我們來遊樂園了，妳這樣不分青紅皂白地撲上去，不就沒有來這裡的意義了嗎？"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"여기 일은 관할 태스크포스에 맡기고, 우리는 지금부터라도 남아 있는 놀이기구나 타러 가는 게 건설적이지 않을까요?","JPN":"ここは管轄のタスクフォースカンパニーに任せて、\\n僕たちはアトラクションにでも乗ったほうが有意義なんじゃないですか？","ENG":"Let’s leave this to whichever TASKFORCE has jurisdiction here. Wouldn't it be more constructive for us to enjoy a few rides while we still can?","TWN":"這裡的工作就交給負責的特遣勢力公司，我們就去玩剩下的遊樂設施吧？"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"시끄러워.","JPN":"うるっさいな。","ENG":"Oh, shut up.","TWN":"吵死了。"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"애초에 놀이공원 같은 곳에 데려가 달라고 한 적도 없거든?","JPN":"そもそも遊園地に連れてってほしいなんて頼んでないから。","ENG":"I never even asked to go to an amusement park in the first place.","TWN":"我本來就沒要求你要帶我來遊樂園。"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"놀고 싶으면 선배나 놀아.","JPN":"遊びたいなら先輩一人で遊べばいいでしょ。","ENG":"You go enjoy yourself if you want.","TWN":"前輩想玩的話就自己去玩吧。"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"난 침식체들 상대하기도 바쁘니까.","JPN":"私は侵食体を倒すことで手一杯なんだから。","ENG":"I've got my hands full with the C.O.'s as it is.","TWN":"我忙著對付侵蝕體呢。"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"뭐 이럴 거라고 생각은 했지만....... 참 전형적인 PTSD 증상이네요.","JPN":"こうなるだろうとは思ってましたが、なんとも典型的なPTSDの症状ですね。","ENG":"Just as I thought... This is a typical symptom of PTSD.","TWN":"雖然我也預料到了這種情況……但這還真是典型的PTSD症狀呢……"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이래서 애초에 놀이공원이 아니라 심리상담 쪽을 추천했었는데.......","JPN":"これだから、遊園地じゃなくて心理カウンセリングの方を勧めたのに……","ENG":"This is exactly why I recommended a psychiatric counseling session over an amusement park...","TWN":"早知道這樣，就不該帶妳來遊樂園，而該推薦妳去看心理諮詢……"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐? 누굴 미친 사람으로 모는 거야?","JPN":"はあ？　私のこと、精神的におかしくなってるとでも？","ENG":"What? Don’t treat me like some crazy person!","TWN":"什麼？你說誰是瘋子？"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"난 멀쩡하다고!","JPN":"私はなんともないってば！","ENG":"I’m perfectly fine!","TWN":"我很正常！"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양. PTSD는 미친 게 아니라 누구든 겪을 수 있는 자연스러운 질환이에요.","JPN":"ミナさん、PTSDはおかしくなってるんじゃなくて、誰でも経験し得る自然な症状なんですよ。","ENG":"Mina. PTSD is something that can happen to anyone.","TWN":"米娜小姐，所謂的PTSD不是發瘋，而是誰都有可能經歷的正常疾病。"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양처럼 짧은 시간 동안 큰 충격을 연속적으로 받을 경우, 특히 더 그렇죠.","JPN":"ミナさんのように、短時間で何度も大きなショックを受けた場合は、特に出やすいんです。","ENG":"Especially those who are repeatedly exposed to acutely shocking incidents in a short time frame, like you.","TWN":"像米娜小姐這樣，短時間內連續受到劇烈刺激的人，特別容易有這種症狀。"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양, 그때 비숍의 말로는 원래 이렇게 거친 성격이 아니었다면서요?","JPN":"ミナさん、あの時のビショップの話だと、元々はこんなに荒っぽい性格じゃなかったんですよね？","ENG":"Didn’t Bishop say that you didn’t always have such a rough personality?","TWN":"米娜小姐，當時主教說妳本來不是這種暴躁的性格，不是嗎？"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"제가 보기엔 성격이 변한 것도 각성 붕괴 사건을 겪으면서 일종의 자기보호기제가 발동......","JPN":"僕が思うに、性格が変わったのは覚醒崩壊事件を経験して、ある種の自己防御本能が働き……","ENG":"I think the change in your personality is some sort of a defense mechanism triggered by your Awakening Collapse...","TWN":"在我看來，妳的性格變化，也是覺醒崩壞造成的一種自我保護機制。"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"시끄럽다고!","JPN":"うるさいって言ったでしょ！","ENG":"That’s enough!","TWN":"你吵死了！"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"충격은 누가 충격을 받았다고 그래?","JPN":"誰がショックを受けたって？","ENG":"Who says I got traumatized?","TWN":"誰說我受到刺激了？"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"내가 그따위 일로 꿈쩍이라도 할 것 같아?","JPN":"私があれっぽっちのことで崩壊するとでも？","ENG":"Think I'd even bat an eye at that crap?","TWN":"我會因為那種事情受到刺激嗎？"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그 녀석은 어차피 죽을 녀석이었어!","JPN":"あいつはどうせ死ぬ運命だったのよ！","ENG":"She was going to die anyway!","TWN":"那個傢伙反正也是個死人！"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아니, 이미 한참 전에 죽었던 시체 같은 거라고!","JPN":"いや、とっくの昔にくたばった屍みたいなものだ！","ENG":"If anything, she was already long dead as far as I knew!","TWN":"不，在那之前還像個已經死掉的屍體！"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그건 나래도, 내 친구도 아니었어!","JPN":"あれはナルミでも、私の友達でもなかった！","ENG":"That thing wasn’t the real Narae... or my friend!","TWN":"那個東西不是娜拉，也不是我的朋友。"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그렇지? 그건......","JPN":"そうでしょ？　あれは……","ENG":"Don’t you see? That thing...","TWN":"對吧？那個……"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그러니까....... 그건.......","JPN":"だから……あれは……","ENG":"I mean... I...","TWN":"所以……那個……"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그건......","JPN":"あれは……","ENG":"I...","TWN":"那個……"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양, 괜찮아요?","JPN":"ミナさん、大丈夫ですか？","ENG":"You okay, Mina?","TWN":"米娜小姐，妳還好嗎？"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......됐어. 도와주지 않을 거면 돌아가.","JPN":"……いいよ、もう。手伝ってくれないなら帰ってよ。","ENG":"Forget it. Just get out of here if you’re not going to help.","TWN":"……算了。你不幫我的話就回去吧。"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"난 남은 잔당들이나 마저 처리할 테니까.","JPN":"私は残党を片付けるから。","ENG":"I’m going to finish cleaning up the rest of them myself.","TWN":"我要把剩餘的敵人都清理乾淨。"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"내 몸이! 내 몸이!!","JPN":"体が、私の体が……！","ENG":"My body! My body!","TWN":"我的身體！我的身體！"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_HOWLING_03"},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"사, 사람 살려!!","JPN":"た、助けて！！","ENG":"Help!!","TWN":"救，救命啊！"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"무, 무슨 일이야? 이건!","JPN":"は？　なに……これ……どういうこと？","ENG":"W-what's going on? What’s this?!","TWN":"怎，怎麼了？這是！"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PARK_DESTROYED","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};